309→        placeholder="Select a category"
310→      />
311→      <FormTagPicker
312→        label="Tags"
313→        value={form.tags}
314→        onChange={v =>
315→          setForm(prev => ({
316→            ...prev,
317→            tags: v,
318→          }))
319→        }
320→        options={FORM_TAG_OPTIONS}
321→        placeholder="Add tags..."
322→        description="Categorize your snippet with tags"
323→      />
324→      <FormTextArea
325→        label="Snippet"
326→        value={form.snippet}
327→        onChange={v =>
328→          setForm(prev => ({
329→            ...prev,
330→            snippet: v,
331→          }))
332→        }
333→        placeholder="Enter your snippet content..."
334→        error={errors.snippet}
335→        rows={5}
336→      />
337→    </Form>
338→  );
339→}
